  ('pukao-d592fc58-moex-00037', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-6948958a', 'sub-pukao-d592fc58-01', NULL, 'single_choice', '下列何者會創造對日元的需求？', '["日本學生到臺灣做交換生", "臺灣人前往日本北海道觀光", "臺灣機械業到泰國投資", "日本海鮮店進口屏東黑鮪魚"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00038', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-6948958a', 'sub-pukao-d592fc58-01', NULL, 'single_choice', '若GDP為國內生產毛額、GNP為國民生產毛額、C為民間消費、I為國內投資、G為政府購買，則淨出口 等於：', '["C+I+G-GNP", "GDP-C-I-G", "C+I+G-GDP", "GNP-C-I-G"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00039', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-6948958a', 'sub-pukao-d592fc58-01', NULL, 'single_choice', '為提振景氣，某國政府擬發放消費券共計 10億元。依據該國政府的估算，其他條件不變之下，此一政策 總共可以提高該國國內生產毛額（GDP）5%。若該國目前的GDP為1,000億元，依據引入政府部門的簡 單凱因斯模型，該國政府估計該國的邊際消費傾向為何？', '["0.2", "0.6", "0.75", "0.8"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00040', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-6948958a', 'sub-pukao-d592fc58-01', NULL, 'single_choice', '經濟不景氣，人們消費需求明顯減少，此時對產出與物價各有何影響？', '["產出下降、物價下降", "產出上升、物價上升", "產出下降、物價上升", "產出上升、物價下降"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00041', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-6948958a', 'sub-pukao-d592fc58-01', NULL, 'single_choice', '假設不考慮國外部門與政府部門。在簡單凱因斯模型裡，如果民間消費函數為 C=10+0.8Y，則自發性支出 乘數等於：', '["2", "5", "8", "10"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00042', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-6948958a', 'sub-pukao-d592fc58-01', NULL, 'single_choice', '在總合供需模型中，若因為中東地區緊張導致原油價格上漲，將使產出 ，實質利率 。', '["上升，上升", "上升，下降", "下降，上升", "下降，下降"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00043', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-6948958a', 'sub-pukao-d592fc58-01', NULL, 'single_choice', '當Y=C+I+G，C=50+0.75Y ，I=100，G=60，Y =Y-T，T=60，且充分就業水準下之實質所得為600，為達 D D 充分就業，自發性支出必須：', '["減少10", "減少15", "增加20", "增加25"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00044', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-6948958a', 'sub-pukao-d592fc58-01', NULL, 'single_choice', '假設某一經濟體系的物價與名目工資在短期均是完全僵固的。根據凱因斯學派，當此一經濟體系的勞動參 與率上升時，則在短期該經濟體系的產出與失業率會如何變動？', '["產出與失業率皆上升", "產出與失業率皆下降", "產出增加，失業率下降", "產出不變，失業率上升"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00045', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-6948958a', 'sub-pukao-d592fc58-01', NULL, 'single_choice', '有關總合需求政策，下列何者錯誤？', '["經濟預測困難是部份經濟學家不贊成主動積極型總合需求政策的原因之一", "總合需求政策的施行及其效果的時間落後（lagsofimplementationformacroeconomicpolicies）是部份經 濟學家不贊成採行主動積極型總合需求政策的原因", "貨幣政策的內在時間落後（insidelag）很短，外在時間落後（outsidelag）長", "財政政策的內在時間落後很短，是經濟學家認為需要採行反景氣循環政策時，財政政策應優先於貨幣政策"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00046', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-6948958a', 'sub-pukao-d592fc58-01', NULL, 'single_choice', '根據流動性偏好理論（theoryofliquiditypreference），下列何者會調整至使貨幣供需達成平衡的水準？', '["一般物價", "GDP", "利率", "匯率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL)
